#nullable enable // autogenerated

namespace MVZ2Logic.Options
{
    public abstract class OptionSliderDefinition : OptionWidgetDefinition
    {
        public OptionSliderDefinition(string nsp, string name) : base(nsp, name)
        {
        }
        public override OptionWidgetType GetItemType()
        {
            return OptionWidgetType.Slider;
        }
        public abstract float GetValue(IOptionContext context);
        public abstract string GetLabelValue(IOptionContext context, float value);
        public abstract void OnValueChanged(IOptionContext context, float value);
        public abstract void OnEndEdit(IOptionContext context, float value);
    }
}
